module RefModule (  
    input wire clk,  
    input wire we,  
    input wire [15:0] data_in,  
    output reg [15:0] data_out  
);  
    reg [15:0] obf_storage;  

    always @(posedge clk) begin  
        if (we)  
            obf_storage <= data_in;  
        else  
            data_out <= obf_storage;  
    end  
endmodule
